<?php
declare(strict_types=1);$root=require dirname(__DIR__).'/bootstrap/app.php';use Dompdf\Dompdf;use Dompdf\Options;use Vigilancia\Database\Connection;use Vigilancia\Repositories\AuditRepository;use Vigilancia\Repositories\PermissionRepository;use Vigilancia\Repositories\SecurityLogRepository;use Vigilancia\Services\AuditService;use Vigilancia\Services\AuthService;use Vigilancia\Support\ClientInfo;use Vigilancia\Support\Config;use Vigilancia\Support\Session;Session::start();$pdo=Connection::make(Config::database());$auth=new AuthService($pdo);$actor=$auth->current();$data=(new AuditService(new AuditRepository($pdo),new PermissionRepository($pdo)))->list($actor,$_GET,5000);$e=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');$rows='';foreach($data['items']as$x)$rows.='<tr><td>'.$e($x['occurred_at']).'</td><td>'.$e($x['full_name']?:'Sistema').'</td><td>'.$e($x['event_type']).'</td><td>'.$e($x['record_type']).' #'.$e($x['record_id']).'</td><td>'.$e($x['ip_address']).'</td><td>'.$e($x['context_json']).'</td></tr>';$html='<!doctype html><html lang="es"><head><meta charset="utf-8"><style>@page{margin:25px}body{font:8px DejaVu Sans;color:#0B1D3A}header{background:#0B1D3A;color:white;padding:15px}table{width:100%;border-collapse:collapse}th,td{border:1px solid #d7dee9;padding:5px;word-break:break-word}th{background:#163D7A;color:white}</style></head><body><header><h1>Auditoría · Sistema de Vigilancia</h1><p>Exportación permanente dentro del alcance autorizado</p></header><p>Generado por '.$e($actor['full_name']).' · '.gmdate('Y-m-d H:i:s').' UTC</p><table><thead><tr><th>Fecha</th><th>Usuario</th><th>Acción</th><th>Registro</th><th>IP</th><th>Contexto</th></tr></thead><tbody>'.$rows.'</tbody></table></body></html>';$dompdf=new Dompdf(new Options());$dompdf->loadHtml($html,'UTF-8');$dompdf->setPaper('letter','landscape');$dompdf->render();(new SecurityLogRepository($pdo))->record((int)$actor['id'],'audit.exported',ClientInfo::ip(),ClientInfo::userAgent(),['filters'=>$_GET]);$dompdf->stream('auditoria-'.gmdate('Ymd-His').'.pdf',['Attachment'=>false]);
